from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetPresetScenesNode(BaseNode):
    name = "Prism: Get Preset Scenes"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("extension_filter", "string", widget_type="text", default="")
        self.add_output("presets", "list")
        self.add_output("first_preset", "string")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        ext = (inputs.get('extension_filter') or '').strip().lower()
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'presets': [], 'first_preset': '', 'count': 0}
        try:
            presets = core.entities.getPresetScenes() or []
            if ext:
                if not ext.startswith('.'):
                    ext = '.' + ext
                presets = [p for p in presets if str(p).lower().endswith(ext)]
            first = presets[0] if presets else ''
            self.log_info(f"Found {len(presets)} preset(s).")
            return {'presets': list(presets), 'first_preset': first, 'count': len(presets)}
        except Exception as e:
            self.log_error(f"getPresetScenes failed: {e}")
            return {'presets': [], 'first_preset': '', 'count': 0}

def register_node():
    return PrismGetPresetScenesNode
